// frontend/src/components/Nav.js

import { Link, useLocation, useNavigate } from "react-router-dom";
import { useAuth } from "../context/AuthContext";
import { useEffect } from "react";
import "../App.css";

export default function Nav() {
  const location = useLocation();
  const navigate = useNavigate();
  const { user, logout, loading } = useAuth();

  /* ==============================
      ROLE FIX (IMPORTANT)
  ============================== */
  const role = user?.role?.toLowerCase?.() || "";

  // ✅ FIX: treat "member" as normal user
  const isUser =
    user && (role === "user" || role === "member");

  const isAdmin = user && role === "admin";

  const isGuest = !user && !loading;

  /* ==============================
      ACTIVE LINK HELPER
  ============================== */
  const isActive = (path) =>
    location.pathname === path ? "active" : "";

  /* ==============================
      LOADING STATE
  ============================== */
  if (loading) {
    return (
      <header>
        <nav className="menu">
          <span>Loading...</span>
        </nav>
      </header>
    );
  }

  /* ==============================
      LOGOUT
  ============================== */
  const handleLogout = () => {
    logout();
    localStorage.removeItem("token");
    navigate("/login");
  };

  return (
    <header>
      <h1 className="title">
        Expressing Creativity Through Art and Crafts
      </h1>

      <nav className="menu">

        {/* ================= COMMON LINKS ================= */}
        <Link to="/home" className={isActive("/home")}>HOME</Link>
        <Link to="/about" className={isActive("/about")}>ABOUT</Link>
        <Link to="/contact" className={isActive("/contact")}>CONTACT</Link>

        {/* ================= GUEST ================= */}
        {isGuest && (
          <>
            <Link to="/login" className={isActive("/login")}>
              LOGIN
            </Link>
            <Link to="/register" className={isActive("/register")}>
              REGISTER
            </Link>
          </>
        )}

        {/* ================= USER / MEMBER ================= */}
        {isUser && (
          <>
            <Link to="/create-post" className={isActive("/create-post")}>
              CREATE POST
            </Link>

            <Link to="/profile" className={isActive("/profile")}>
              PROFILE
            </Link>

            <button onClick={handleLogout}>
              LOGOUT
            </button>
          </>
        )}

        {/* ================= ADMIN ================= */}
        {isAdmin && (
          <>
            <Link to="/admin" className={isActive("/admin")}>
              USERS
            </Link>

            <Link to="/posts" className={isActive("/posts")}>
              POSTS
            </Link>

            <Link to="/create-post" className={isActive("/create-post")}>
              CREATE
            </Link>

            <Link to="/edit-post" className={isActive("/edit-post")}>
              EDIT
            </Link>

            <button onClick={handleLogout}>
              LOGOUT
            </button>
          </>
        )}

      </nav>
    </header>
  );
}
